Clear `current_pr_number` whenever a pool slot is released or globally reset.

```js
async markAvailable(id) {
  await run(this.db, `
    UPDATE worktree_pool
    SET status = 'available',
        current_pr_number = NULL
    WHERE id = ?
  `, [id]);
}

async resetAllStatuses() {
  await run(this.db, `
    UPDATE worktree_pool
    SET status = 'available',
        current_pr_number = NULL
  `);
}
```

Restrict `findByPR()` to active assignments only by requiring `status = 'in_use'`.

```js
async findByPR(prNumber, repository) {
  return await queryOne(this.db, `
    SELECT id, repository, path, status, current_pr_number, last_switched_at, last_fetched_at, created_at
    FROM worktree_pool
    WHERE current_pr_number = ? AND repository = ? AND status = 'in_use'
  `, [prNumber, repository]);
}
```

Increase the ID length and add a retry loop before committing the new pool worktree ID.

```js
// src/database.js
function generatePoolWorktreeId(length = 6) {
  const chars = '0123456789abcdefghijklmnopqrstuvwxyz';
  let randomPart = '';
  for (let i = 0; i < length; i++) {
    randomPart += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return `pool-${randomPart}`;
}
